package com.rabitah.frontend.controller;
import com.rabitah.frontend.AppContext; import javafx.application.Platform; import javafx.fxml.FXML; import javafx.scene.control.*;
public final class LoginController {private final AppContext context;@FXML private TextField loginId;@FXML private PasswordField password;@FXML private Button loginButton;@FXML private Label errorLabel;public LoginController(AppContext context){this.context=context;}@FXML private void login(){errorLabel.setText("");loginButton.setDisable(true);context.auth().login(loginId.getText().trim(),password.getText()).whenComplete((response,error)->Platform.runLater(()->{loginButton.setDisable(false);if(error!=null){Throwable cause=error.getCause()==null?error:error.getCause();errorLabel.setText(cause.getMessage());return;}context.session().open(response);context.router().showShell();}));}}
